const allItems = $input.all();

const metricas = allItems.find(i => i.json.total_triajes !== undefined)?.json || { total_triajes: 0, criticos: 0, altos: 0, moderados: 0, bajos: 0 };
const porProfesional = allItems.filter(i => i.json.profesional !== undefined);
const porHora = allItems.filter(i => i.json.hora !== undefined);

const fecha = new Date().toLocaleDateString('es-CO', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const html = `<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; margin: 40px; }
    h1 { color: #2c3e50; border-bottom: 2px solid #3498db; padding-bottom: 10px; }
    h2 { color: #34495e; margin-top: 30px; }
    table { width: 100%; border-collapse: collapse; margin: 20px 0; }
    th, td { border: 1px solid #ddd; padding: 12px; text-align: left; }
    th { background-color: #3498db; color: white; }
    tr:nth-child(even) { background-color: #f9f9f9; }
    .metric-box { display: inline-block; width: 150px; padding: 20px; margin: 10px; background: #ecf0f1; border-radius: 8px; text-align: center; }
    .metric-value { font-size: 2em; font-weight: bold; color: #2c3e50; }
    .metric-label { font-size: 0.9em; color: #7f8c8d; }
    .critico { color: #e74c3c; }
    .alto { color: #e67e22; }
    .moderado { color: #f39c12; }
    .bajo { color: #27ae60; }
  </style>
</head>
<body>
  <h1>Reporte Diario de Triajes</h1>
  <p><strong>Fecha:</strong> ${fecha}</p>
  <h2>Resumen General</h2>
  <div class="metric-box"><div class="metric-value">${metricas.total_triajes || 0}</div><div class="metric-label">Total Triajes</div></div>
  <div class="metric-box"><div class="metric-value critico">${metricas.criticos || 0}</div><div class="metric-label">Criticos</div></div>
  <div class="metric-box"><div class="metric-value alto">${metricas.altos || 0}</div><div class="metric-label">Altos</div></div>
  <div class="metric-box"><div class="metric-value moderado">${metricas.moderados || 0}</div><div class="metric-label">Moderados</div></div>
  <div class="metric-box"><div class="metric-value bajo">${metricas.bajos || 0}</div><div class="metric-label">Bajos</div></div>
  <h2>Triajes por Profesional</h2>
  <table><tr><th>Profesional</th><th>Cantidad</th></tr>
  ${porProfesional.length > 0 ? porProfesional.map(p => `<tr><td>${p.json.profesional || 'N/A'}</td><td>${p.json.cantidad_triajes || 0}</td></tr>`).join('') : '<tr><td colspan="2">No hay datos</td></tr>'}
  </table>
  <h2>Distribucion por Hora</h2>
  <table><tr><th>Hora</th><th>Cantidad</th></tr>
  ${porHora.length > 0 ? porHora.map(h => `<tr><td>${new Date(h.json.hora).toLocaleTimeString('es-CO')}</td><td>${h.json.cantidad || 0}</td></tr>`).join('') : '<tr><td colspan="2">No hay datos</td></tr>'}
  </table>
  <p><em>Generado automaticamente por el Sistema de Triaje IA.</em></p>
</body>
</html>`;

return [{ json: { html } }];
